using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build the AI chat client with automatic function-calling support
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Instantiate tools the agent can use
// ---------------------------------------------------------------------------
var webSearch = new WebSearchTool();
var notebook  = new NotebookTool();

// ---------------------------------------------------------------------------
// Create the research agent
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and taking notes, then summarises findings.",
    instructions: """
        You are a research agent. Your goal is to thoroughly research the user's topic
        using the tools at your disposal, then provide a well-organised summary.

        Follow this approach:
        1. Perform 2-3 web searches with varied queries to gather broad information.
        2. For every useful fact or insight you find, save it as a note.
        3. Once you have enough material, retrieve your notes and compose a
           comprehensive, well-structured summary for the user.

        Always search before summarising. Never fabricate information — only report
        what you found through the search tool.
        """,
    tools:
    [
        AIFunctionFactory.Create(webSearch.SearchAsync),
        AIFunctionFactory.Create(notebook.SaveNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ]);

// ---------------------------------------------------------------------------
// Prompt for a research topic and run the agent
// ---------------------------------------------------------------------------
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided — exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

var session = new ChatClientAgentSession();
AgentResponse response = await agent.RunAsync($"Please research the following topic and provide a summary:\n\n{topic}", session);

Console.WriteLine("\n════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

// ═══════════════════════════════════════════════════════════════════════════
// Tool definitions
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Searches the web via DuckDuckGo's HTML endpoint and returns result snippets.</summary>
sealed class WebSearchTool
{
    private readonly HttpClient _http = new();

    [Description("Search the web for information on a query. Returns relevant result snippets.")]
    public async Task<string> SearchAsync([Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var httpResponse = await _http.SendAsync(request);
            var html = await httpResponse.Content.ReadAsStringAsync();

            var snippets = ExtractSnippets(html);
            return snippets.Count > 0
                ? string.Join('\n', snippets)
                : "No results found. Try rephrasing your query.";
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). Try a different query.";
        }
    }

    private static List<string> ExtractSnippets(string html)
    {
        var results = new List<string>();

        // DuckDuckGo HTML results use class="result__snippet" for the summary text.
        foreach (Match m in Regex.Matches(html, @"class=""result__snippet[^""]*""[^>]*>(.*?)</", RegexOptions.Singleline))
        {
            var text = WebUtility.HtmlDecode(
                Regex.Replace(m.Groups[1].Value, "<[^>]+>", " ")).Trim();

            if (!string.IsNullOrWhiteSpace(text))
                results.Add($"• {text}");

            if (results.Count >= 6) break;
        }

        return results;
    }
}

/// <summary>Simple in-memory notebook for storing and retrieving research findings.</summary>
sealed class NotebookTool
{
    private readonly List<string> _notes = [];

    [Description("Save an important research finding as a note for later reference.")]
    public string SaveNote([Description("The content of the note to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝  Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all previously saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  📋  Retrieved {_notes.Count} note(s)");
        return string.Join('\n', _notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

